import{_ as a,o as t,c as o,ag as i}from"./chunks/framework.NIzFHKo_.js";const p=JSON.parse('{"title":"Legacy CSV Migration Plan & Audit","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/60_knowledge/40_legacy_csv_migration_plan.md","filePath":"10_core/60_knowledge/40_legacy_csv_migration_plan.md"}'),n={name:"10_core/60_knowledge/40_legacy_csv_migration_plan.md"};function c(s,e,r,d,l,m){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="legacy-csv-migration-plan-audit" tabindex="-1">Legacy CSV Migration Plan &amp; Audit <a class="header-anchor" href="#legacy-csv-migration-plan-audit" aria-label="Permalink to &quot;Legacy CSV Migration Plan &amp; Audit&quot;">​</a></h1><h2 id="_1-executive-summary" tabindex="-1">1. Executive Summary <a class="header-anchor" href="#_1-executive-summary" aria-label="Permalink to &quot;1. Executive Summary&quot;">​</a></h2><p>The legacy CSV corpus contains immense operational value spanning CRM, accounting, and proprietary knowledge extraction. However, it is heavily polluted with duplicate subsets, deprecated structural matrixes, and extremely sensitive plaintext credential exports.</p><p>Importing this data directly into the canonical <code>qione</code> or <code>qiarchive</code> schemas is prohibited. It would violate single-source-of-truth principles and expose the system to dirty, non-normalized types.</p><p>Instead, all imported files must pass through <code>staging</code> isolated tables before mapped normalization.</p><h2 id="_2-sensitive-quarantine-list-🚨" tabindex="-1">2. Sensitive / Quarantine List 🚨 <a class="header-anchor" href="#_2-sensitive-quarantine-list-🚨" aria-label="Permalink to &quot;2. Sensitive / Quarantine List 🚨&quot;">​</a></h2><p><strong>IMMEDIATE ACTION</strong>: The following files must be relocated to an offline encrypted store (e.g., 1Password or physical vault) and permanently shredded from the migration workspace. They must <strong>never</strong> touch Supabase or any web-facing database schema.</p><ul><li><code>Chrome Passwords.csv</code> - Contains clear text browser credentials.</li><li><code>API Recovery Keys ... .csv</code> - Contains unencrypted infrastructure break-glass keys.</li></ul><h2 id="_3-migration-families" tabindex="-1">3. Migration Families <a class="header-anchor" href="#_3-migration-families" aria-label="Permalink to &quot;3. Migration Families&quot;">​</a></h2><p>Files have been bucketed into 6 structural families to allow incremental, logical migration.</p><h3 id="family-1-contacts-crm-the-entry-point" tabindex="-1">Family 1: Contacts &amp; CRM (The Entry Point) <a class="header-anchor" href="#family-1-contacts-crm-the-entry-point" aria-label="Permalink to &quot;Family 1: Contacts &amp; CRM (The Entry Point)&quot;">​</a></h3><ul><li><code>contacts_cleaned.csv</code>, <code>contact_merged.csv</code>, <code>vendors_merged.csv</code></li></ul><h3 id="family-2-knowledge-blueprint-memory" tabindex="-1">Family 2: Knowledge &amp; Blueprint Memory <a class="header-anchor" href="#family-2-knowledge-blueprint-memory" aria-label="Permalink to &quot;Family 2: Knowledge &amp; Blueprint Memory&quot;">​</a></h3><ul><li><code>20251116_biz_ai_kb_full.csv</code>, <code>20251116_biz_blueprints_workflows_list.csv</code></li><li><code>Notes_001.csv</code>, <code>gina_memory_rows.csv</code></li></ul><h3 id="family-3-communications-timeline" tabindex="-1">Family 3: Communications &amp; Timeline <a class="header-anchor" href="#family-3-communications-timeline" aria-label="Permalink to &quot;Family 3: Communications &amp; Timeline&quot;">​</a></h3><ul><li><code>raw_emails_combined.csv</code>, <code>db_RawEmails_KB ... .csv</code>, <code>Emails_001.csv</code></li><li><code>conversations.csv</code>, <code>Meetings_001.csv</code>, <code>qimessages_C_001.csv</code></li></ul><h3 id="family-4-catalog-services" tabindex="-1">Family 4: Catalog &amp; Services <a class="header-anchor" href="#family-4-catalog-services" aria-label="Permalink to &quot;Family 4: Catalog &amp; Services&quot;">​</a></h3><ul><li><code>master_services_catalog__all.csv</code>, <code>service_matrix.csv</code>, <code>Products_001.csv</code></li></ul><h3 id="family-5-finance-accounting" tabindex="-1">Family 5: Finance &amp; Accounting <a class="header-anchor" href="#family-5-finance-accounting" aria-label="Permalink to &quot;Family 5: Finance &amp; Accounting&quot;">​</a></h3><ul><li><code>Internal COA (OS)...csv</code>, <code>QiCode_Chart_of_Accounts_Mapping.csv</code></li><li><code>Sales Orders_001.csv</code>, <code>Ordered Items_001.csv</code>, <code>Quoted Items_001.csv</code>, <code>Invoices_001.csv</code></li></ul><h3 id="family-6-governance-system-metadata-archive-preserve-only" tabindex="-1">Family 6: Governance &amp; System Metadata (Archive/Preserve Only) <a class="header-anchor" href="#family-6-governance-system-metadata-archive-preserve-only" aria-label="Permalink to &quot;Family 6: Governance &amp; System Metadata (Archive/Preserve Only)&quot;">​</a></h3><ul><li><code>qios_rules_v1_1.csv</code>, <code>qios_matrix.csv</code>, <code>front_matter_schema_v1.csv</code></li><li><code>realms_registry.csv</code>, <code>sensitivity_classification_*.csv</code></li><li><code>Roles_001.csv</code>, <code>Modules_001.csv</code>, <code>file_system_nodes.csv</code></li></ul><hr><h2 id="_4-staging-schema-proposal" tabindex="-1">4. Staging Schema Proposal <a class="header-anchor" href="#_4-staging-schema-proposal" aria-label="Permalink to &quot;4. Staging Schema Proposal&quot;">​</a></h2><p>A dedicated <code>staging</code> schema is required inside Supabase. This acts as Zone B.</p><p><strong>Zone A</strong> - Immutable Raw files (Stored on S3/Disk) <strong>Zone B</strong> - <code>staging.raw_*</code> (Supabase: direct 1:1 CSV column dumps, text types only) <strong>Zone C</strong> - <code>staging.norm_*</code> (Supabase: SQL views/tables converting dates, mapping UUIDs) <strong>Zone D</strong> - Canonical Domains (e.g., <code>qione.contact</code>, <code>qicase.event</code>, <code>qihome.invoice</code>)</p><h3 id="expected-staging-tables" tabindex="-1">Expected Staging Tables: <a class="header-anchor" href="#expected-staging-tables" aria-label="Permalink to &quot;Expected Staging Tables:&quot;">​</a></h3><ul><li><code>staging.csv_import_batches</code> (Tracks migration jobs)</li><li><code>staging.raw_contacts</code></li><li><code>staging.raw_companies</code></li><li><code>staging.raw_notes</code></li><li><code>staging.raw_emails</code></li><li><code>staging.raw_messages</code></li><li><code>staging.raw_transactions</code></li><li><code>staging.raw_products</code></li><li><code>staging.raw_services</code></li><li><code>staging.raw_blueprints</code></li><li><code>staging.raw_agent_memory</code></li></ul><hr><h2 id="_5-canonical-destination-mapping" tabindex="-1">5. Canonical Destination Mapping <a class="header-anchor" href="#_5-canonical-destination-mapping" aria-label="Permalink to &quot;5. Canonical Destination Mapping&quot;">​</a></h2><p>Once Zone C (normalized views) establishes clean relationships and valid types, data will be piped to canonical tables owned by specific downstream domains:</p><table tabindex="0"><thead><tr><th>Family</th><th>Staging Norm View</th><th>Canonical Target</th></tr></thead><tbody><tr><td><strong>Contacts</strong></td><td><code>staging.norm_contacts</code></td><td><code>qione.contact</code>, <code>qione.organization</code></td></tr><tr><td><strong>Knowledge</strong></td><td><code>staging.norm_notes</code></td><td><code>qiknowledge.note</code>, <code>qiarchive.file_record</code></td></tr><tr><td><strong>Emails/Comms</strong></td><td><code>staging.norm_messages</code></td><td><code>qicase.communication</code>, <code>qivault.raw_extract</code></td></tr><tr><td><strong>Finance</strong></td><td><code>staging.norm_transactions</code></td><td><code>qihome.transaction</code>, <code>qihome.invoice</code></td></tr><tr><td><strong>Catalog</strong></td><td><code>staging.norm_services</code></td><td><code>qihome.service_tier</code>, <code>qione.product</code></td></tr></tbody></table><hr><h2 id="_6-matrix-disposition" tabindex="-1">6. Matrix &amp; Disposition <a class="header-anchor" href="#_6-matrix-disposition" aria-label="Permalink to &quot;6. Matrix &amp; Disposition&quot;">​</a></h2><p>Every file maps to one of four rules:</p><ol><li><strong>Quarantine</strong>: Shred from disk. Never import. (Passwords, Keys)</li><li><strong>Archive</strong>: Superseded by current blueprint. Do not import. Keep for reference. (Legacy governance matrixes)</li><li><strong>Preserve Only</strong>: Keep raw but do not import. System irrelevant. (Roles, file system nodes)</li><li><strong>Migrate</strong>: Send to staging. (Contacts, KBs, Emails, Finance)</li></ol><h2 id="_7-action-plan-first-10-steps" tabindex="-1">7. Action Plan: First 10 Steps <a class="header-anchor" href="#_7-action-plan-first-10-steps" aria-label="Permalink to &quot;7. Action Plan: First 10 Steps&quot;">​</a></h2><p>To prevent contamination, we will prove the pipeline with the <strong>Contacts</strong> family first.</p><ol><li><strong>Delete &amp; Shred</strong> <code>Chrome Passwords.csv</code> and <code>API Recovery Keys</code> from the staging directory to prevent accidental upload.</li><li>Initialize <code>staging</code> schema via a new standard Supabase migration file.</li><li>Create generic <code>staging.csv_import_batches</code> to track what file was ingested when.</li><li>Create empty table <code>staging.raw_contacts</code> with <code>TEXT</code> column types matching the header of <code>contacts_cleaned.csv</code>.</li><li>Write a small Python ingestion script using <code>supabase-py</code> or <code>psycopg2</code> to upload <code>contacts_cleaned.csv</code> into <code>raw_contacts</code>.</li><li>Query <code>staging.raw_contacts</code> to find distinct states, nulls, and duplicate email addresses.</li><li>Create <code>staging.norm_contacts</code> view casting text to timestamps, booleans, and generating deterministic UUIDs (e.g., using <code>uuid_generate_v5</code> against the email).</li><li>Verify the <code>norm_contacts</code> entity shape against the blueprint&#39;s <code>qione.contact</code> requirements.</li><li>Execute a bulk <code>INSERT INTO qione.contact SELECT * FROM staging.norm_contacts</code>.</li><li>Once CRM data is verified live in the Admin portal, repeat steps 4-9 for <strong>Knowledge</strong> (using <code>Notes_001.csv</code>).</li></ol>',39)])])}const h=a(n,[["render",c]]);export{p as __pageData,h as default};
